    // Fold: (zext i1 X) + (zext i1 Y) == 1  -->  X ^ Y
    //       (zext i1 X) + (zext i1 Y) != 1  -->  ~(X ^ Y)
    // This checks if both operands are zext from i1 and we're comparing the sum
    // against 1. The sum is 1 iff exactly one of X, Y is true, which is xor.
    {
      Value *X, *Y;
      if (C.isOne() &&
          match(BOp0, m_ZExt(m_Value(X))) &&
          match(BOp1, m_ZExt(m_Value(Y))) &&
          X->getType()->isIntegerTy(1) &&
          Y->getType()->isIntegerTy(1)) {
        // (X + Y) == 1 means exactly one is true: X xor Y (i.e., X != Y)
        // (X + Y) != 1 means both or neither: !(X xor Y) (i.e., X == Y)
        Value *Xor = Builder.CreateXor(X, Y);
        if (Pred == ICmpInst::ICMP_EQ)
          return BinaryOperator::CreateNot(Xor);
        return replaceInstUsesWith(Cmp, Xor);
      }
    }
